    getNodePosition(){
        return this.node.position;
    }

    setMoving(direction, isMoving = false) {
        switch (direction) {
            case MoveDirection.LEFT:
                this.isMovingLeft = isMoving;
                break;
            case MoveDirection.RIGHT:
                this.isMovingRight = isMoving;
                break;
            case MoveDirection.UP:
                this.isMovingUp = isMoving;
                break;
            case MoveDirection.DOWN:
                this.isMovingDown = isMoving;
                break;
        }
    }

    onPressMove(direction) {
        this.setMoving(direction, true);
    }

    onPressStop(direction) {
        this.setMoving(direction, false);
    }

    limitPositionOnScene() {
        if (this.node.getPosition().x < -this.canvas.width / 2 + charProps.scencePaddingLeft) {
            this.node.getPosition().x = -this.canvas.width / 2 + charProps.scencePaddingLeft;
        }
        if (this.node.getPosition().x > this.canvas.width / 2 - charProps.scencePaddingRight) {
            this.node.getPosition().x = this.canvas.width / 2 - charProps.scencePaddingRight;
        }
        if (this.node.getPosition().y < -this.canvas.height / 2 + charProps.scencePaddingBottom) {
            this.node.getPosition().y = -this.canvas.height / 2 + charProps.scencePaddingBottom;
        }
        if (this.node.getPosition().y > this.canvas.height / 2 - charProps.scencePaddingTop) {
            this.node.getPosition().y = this.canvas.height / 2 - charProps.scencePaddingTop;
        }
    }

    onMove(dt) {
        if (this.isReload && !this.preReload) {
            return;
        }
        let moveX = 0;
        let moveY = 0;

        if (this.isMovingRight) moveX += 1;
        if (this.isMovingLeft) moveX -= 1;
        if (this.isMovingUp) moveY += 1;
        if (this.isMovingDown) moveY -= 1;

        if (moveX !== 0 || moveY !== 0) {
            this.node.x += moveX * this.speed * dt;
            this.node.y += moveY * this.speed * dt;
            this.isMoving = true;
        }
        else {
            this.isMoving = false;
        }
        this.limitPositionOnScene();
    }

